<?php
namespace Tests\Feature;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Hunts\Rewards\Claim\HuntRewardClaimService;use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Domain\Support\DragonHeroUuid;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterItem;use App\Models\HuntReward;use App\Models\HuntingSession;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\MonsterLootEntry;use App\Models\User;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\CharacterLevelRequirementSeeder;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class ItemInstanceClaimTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);$this->seed(CharacterLevelRequirementSeeder::class);CarbonImmutable::setTestNow('2026-07-16 12:00:00');MonsterLootEntry::query()->update(['drop_probability_ppm'=>1000000,'minimum_quantity'=>1,'maximum_quantity'=>1]);}protected function tearDown():void{CarbonImmutable::setTestNow();parent::tearDown();}private function reward($quantity=1){$character=Character::factory()->for(User::factory())->create(['base_attack'=>500]);$zone=Zone::where('code','grey_oak_forest')->firstOrFail();$service=app(HuntingSessionService::class);$session=HuntingSession::find($service->start($character,$zone)->id());$service->tick($character,$session);$reward=HuntReward::latest('id')->firstOrFail();$line=$reward->items()->firstOrFail();$line->item->update(['is_stackable'=>false,'max_stack'=>1]);$line->update(['quantity'=>$quantity]);return[$character,$reward,$line];}public function test_unique_reward_creates_one_instance_and_event_without_aggregate(){list($character,$reward,$line)=$this->reward();$result=app(HuntRewardClaimService::class)->claimAllPendingForCharacter($character)->toArray();$this->assertSame(1,ItemInstance::count());$this->assertSame(1,ItemInstanceEvent::count());$this->assertFalse(CharacterItem::where('item_id',$line->item_id)->exists());$instance=ItemInstance::first();$this->assertSame($line->id,(int)$instance->origin_id);$this->assertSame(1,$instance->origin_unit_index);$this->assertSame($result['operation_uuid'],ItemInstanceEvent::first()->operation_uuid);$this->assertCount(1,$result['claimed_item_instances']);}public function test_quantity_three_creates_distinct_origin_units_and_double_claim_is_idempotent(){list($character,$reward,$line)=$this->reward(3);$service=app(HuntRewardClaimService::class);$first=$service->claimAllPendingForCharacter($character)->toArray();$this->assertSame([1,2,3],ItemInstance::orderBy('origin_unit_index')->pluck('origin_unit_index')->all());$this->assertSame(3,ItemInstanceEvent::count());$second=$service->claimAllPendingForCharacter($character)->toArray();$this->assertNull($second['operation_uuid']);$this->assertSame(3,ItemInstance::count());$expected=DragonHeroUuid::versionFive('hunt-reward-claim:v1:'.$character->id.':'.$reward->id);$this->assertSame($expected,$first['operation_uuid']);}public function test_inconsistent_item_classifications_are_rejected(){foreach([[true,1],[false,2]] as $state){list($character,$reward,$line)=$this->reward();$item=$line->item;$item->update(['is_stackable'=>$state[0],'max_stack'=>$state[1]]);try{app(HuntRewardClaimService::class)->claimAllPendingForCharacter($character);$this->fail();}catch(\InvalidArgumentException $e){$this->assertStringContainsString('classification',$e->getMessage());}$this->assertSame(0,ItemInstance::count());$this->assertNull($reward->fresh()->claimed_at);$item->update(['is_stackable'=>false,'max_stack'=>1]);$reward->delete();}}
public function test_restricted_item_can_drop_and_be_claimed_but_is_rejected_only_when_equipped(){$mage=CharacterClass::factory()->create(['code'=>'claim_mage']);MonsterLootEntry::with('item')->get()->each(function($entry)use($mage){$entry->item->update(['item_type'=>'equipment','equipment_type'=>'weapon','is_stackable'=>false,'max_stack'=>1,'required_level'=>10]);$entry->item->allowedCharacterClasses()->sync([$mage->id]);});list($character,$reward,$line)=$this->reward();$lootItem=$line->item;app(HuntRewardClaimService::class)->claimAllPendingForCharacter($character);$instance=ItemInstance::where('character_id',$character->id)->where('item_id',$lootItem->id)->firstOrFail();$this->assertSame('available',$instance->status);try{app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'main_hand');$this->fail('Expected equipment requirement rejection.');}catch(\InvalidArgumentException $e){$this->assertTrue(true);}$this->assertSame('available',$instance->fresh()->status);$this->assertTrue($reward->fresh()->claimed_at!==null);}}
